/// Reads a value from a raw pointer.
///
/// # Safety
///
/// - `ptr` must be non-null
/// - `ptr` must point to a valid, initialized `T`
/// - `ptr` must be properly aligned
/// - The memory must not be concurrently mutated
unsafe fn read_ptr<T: Copy>(ptr: *const T) -> T {
    *ptr
}

fn main() {
    let value = 42i32;
    let ptr: *const i32 = &value;

    // Caller verifies safety requirements:
    // - ptr is from a valid reference, so it's non-null, valid, and aligned
    // - value is not being mutated concurrently
    let result = unsafe { read_ptr(ptr) };
    println!("Read: {}", result);
}

/// A fixed-size ring buffer.
struct RingBuffer<T> {
    buffer: Vec<T>,
    head: usize,
    len: usize,
}

impl<T: Default + Clone> RingBuffer<T> {
    fn new(capacity: usize) -> Self {
        RingBuffer {
            buffer: vec![T::default(); capacity],
            head: 0,
            len: 0,
        }
    }

    fn push(&mut self, value: T) {
        let capacity = self.buffer.len();
        let index = (self.head + self.len) % capacity;

        // Safe because we ensure index is always in bounds
        // through the modulo operation
        unsafe {
            *self.buffer.get_unchecked_mut(index) = value;
        }

        if self.len < capacity {
            self.len += 1;
        } else {
            self.head = (self.head + 1) % capacity;
        }
    }

    fn get(&self, index: usize) -> Option<&T> {
        if index >= self.len {
            return None;
        }
        let actual = (self.head + index) % self.buffer.len();
        Some(&self.buffer[actual])
    }
}

fn main() {
    let mut rb = RingBuffer::new(3);
    rb.push(1);
    rb.push(2);
    rb.push(3);
    rb.push(4);  // Overwrites 1

    println!("{:?}", rb.get(0));  // Some(2)
    println!("{:?}", rb.get(1));  // Some(3)
    println!("{:?}", rb.get(2));  // Some(4)
}

use std::cell::UnsafeCell;

/// A very simple mutex for demonstration.
/// In real code, use std::sync::Mutex.
struct SimpleLock<T> {
    data: UnsafeCell<T>,
    locked: std::sync::atomic::AtomicBool,
}

// SAFETY: SimpleLock synchronizes access via the atomic flag,
// so it is safe to share between threads.
unsafe impl<T: Send> Sync for SimpleLock<T> {}
unsafe impl<T: Send> Send for SimpleLock<T> {}

impl<T> SimpleLock<T> {
    fn new(value: T) -> Self {
        SimpleLock {
            data: UnsafeCell::new(value),
            locked: std::sync::atomic::AtomicBool::new(false),
        }
    }

    fn lock(&self) -> &mut T {
        use std::sync::atomic::Ordering;
        // Spin until we acquire the lock
        while self.locked.compare_exchange(
            false, true, Ordering::Acquire, Ordering::Relaxed
        ).is_err() {
            std::hint::spin_loop();
        }
        unsafe { &mut *self.data.get() }
    }

    fn unlock(&self) {
        use std::sync::atomic::Ordering;
        self.locked.store(false, Ordering::Release);
    }
}
